#!/usr/bin/env bash
set -euo pipefail
[[ ${EUID} -eq 0 ]] || { echo "Run as root"; exit 1; }
export DEBIAN_FRONTEND=noninteractive
[[ -f /etc/vpn-install.env ]] && source /etc/vpn-install.env
APP_DIR="${APP_DIR:-/var/www/html/panel-admin}"
DATA_DIR="$APP_DIR/data"
DOWNLOAD_DIR="$APP_DIR/downloads"
ADMIN_USER="${ADMIN_USER:-openvpn}"
ADMIN_PASS="${ADMIN_PASS:-Easin112233@}"
SERVER_ADDR="${SERVER_ADDR:-$(curl -4 -fsSL https://api.ipify.org 2>/dev/null || hostname -I | awk '{print $1}')}"
UDP_PORT="${UDP_PORT:-1194}"; TCP_PORT="${TCP_PORT:-8443}"; OC_PORT="${OC_PORT:-443}"; V2_PORT="${V2_PORT:-4443}"
apt-get update >/dev/null 2>&1 || true
apt-get install -y apache2 php libapache2-mod-php php-sqlite3 php-cli sqlite3 curl sudo >/dev/null 2>&1 || true
mkdir -p "$APP_DIR" "$DATA_DIR" "$DOWNLOAD_DIR"
# Admin DB fallback
if [[ ! -f "$DATA_DIR/ovpn.sqlite" ]]; then
sqlite3 "$DATA_DIR/ovpn.sqlite" <<'SQL'
CREATE TABLE IF NOT EXISTS admins(id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS users(id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, blocked INTEGER NOT NULL DEFAULT 0, notes TEXT DEFAULT '', created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS connection_events(id INTEGER PRIMARY KEY AUTOINCREMENT,event_type TEXT,event_time TEXT DEFAULT CURRENT_TIMESTAMP,username TEXT,common_name TEXT,real_ip TEXT,virtual_ip TEXT,platform TEXT,platform_version TEXT,openvpn_version TEXT,gui_version TEXT,ssl_library TEXT,hwaddr TEXT,time_duration INTEGER DEFAULT 0,rx_bytes INTEGER DEFAULT 0,tx_bytes INTEGER DEFAULT 0,raw_peer_info TEXT,app_hint TEXT);
SQL
fi
ADMIN_HASH="$(php -r "echo password_hash('${ADMIN_PASS}', PASSWORD_DEFAULT);")"
sqlite3 "$DATA_DIR/ovpn.sqlite" "INSERT OR IGNORE INTO admins(username,password_hash) VALUES('${ADMIN_USER}','$ADMIN_HASH');" || true
cat >"$APP_DIR/config.php" <<'PHP'
<?php
session_start(); date_default_timezone_set('UTC');
define('DB_PATH', __DIR__.'/data/ovpn.sqlite'); define('DOWNLOAD_DIR', __DIR__.'/downloads');
function db(){ static $db=null; if($db===null){ $db=new SQLite3(DB_PATH); $db->busyTimeout(5000);} return $db; }
function esc($v){ return htmlspecialchars((string)$v, ENT_QUOTES, 'UTF-8'); }
function require_login(){ if(empty($_SESSION['admin_user'])){ header('Location: login.php'); exit; } }
function admin_login($u,$p){ $st=db()->prepare('SELECT username,password_hash FROM admins WHERE username=:u LIMIT 1'); $st->bindValue(':u',$u,SQLITE3_TEXT); $r=$st->execute(); $row=$r?$r->fetchArray(SQLITE3_ASSOC):false; return $row && password_verify($p,$row['password_hash']); }
function cli($cmd){ exec($cmd.' 2>&1',$out,$code); return [$code, implode("\n",$out)]; }
function protocol_enabled($key){ $f='/etc/vpn-protocols.conf'; if(!is_file($f)) return true; $a=parse_ini_file($f); return !empty($a[$key]) && (string)$a[$key] !== '0'; }
function vpn_env($key,$default=''){ $f='/etc/vpn-install.env'; if(is_file($f)){ $a=parse_ini_file($f); if(isset($a[$key])) return $a[$key]; } $f='/etc/vpn.env'; if(is_file($f)){ $a=parse_ini_file($f); if(isset($a[$key])) return $a[$key]; } return $default; }
function profile_path($u){ return DOWNLOAD_DIR.'/'.basename($u).'.ovpn'; }
function human_bytes($bytes){ $bytes=(float)$bytes; $units=['B','KB','MB','GB','TB']; $i=0; while($bytes>=1024 && $i<count($units)-1){$bytes/=1024;$i++;} return ($i===0?(string)(int)$bytes:number_format($bytes,2)).' '.$units[$i]; }
function users_all(){ if(!protocol_enabled('OPENVPN')) return []; $res=db()->query("SELECT id,username,blocked,created_at,updated_at FROM users ORDER BY id DESC"); $rows=[]; if($res) while($row=$res->fetchArray(SQLITE3_ASSOC)) $rows[]=$row; return $rows; }
function latest_logs($limit=80){ $st=db()->prepare("SELECT * FROM connection_events WHERE event_type='connect' ORDER BY id DESC LIMIT :l"); $st->bindValue(':l',(int)$limit,SQLITE3_INTEGER); $r=$st->execute(); $rows=[]; if($r) while($row=$r->fetchArray(SQLITE3_ASSOC)) $rows[]=$row; return $rows; }
function parse_status_file($file){ $rows=[]; if(!is_file($file)||!is_readable($file)) return $rows; foreach(file($file, FILE_IGNORE_NEW_LINES|FILE_SKIP_EMPTY_LINES) as $line){ $line=trim($line); if(strpos($line,'CLIENT_LIST')!==0) continue; $p=preg_split('/[,\t]/',$line); if(!$p||count($p)<3) continue; $rows[]=['common_name'=>$p[1]??'', 'real_address'=>$p[2]??'', 'virtual_address'=>$p[3]??'', 'bytes_received'=>(int)($p[5]??0), 'bytes_sent'=>(int)($p[6]??0), 'connected_since'=>$p[7]??'', 'username'=>$p[9]??($p[1]??''), 'source'=>'']; } return $rows; }
function last_gui_for_user($username){ $st=db()->prepare("SELECT gui_version FROM connection_events WHERE username=:u AND COALESCE(gui_version,'')<>'' ORDER BY id DESC LIMIT 1"); $st->bindValue(':u',$username,SQLITE3_TEXT); $r=$st->execute(); $row=$r?$r->fetchArray(SQLITE3_ASSOC):false; return $row['gui_version'] ?? ''; }
function active_clients(){ if(!protocol_enabled('OPENVPN')) return []; $rows=[]; foreach(['/var/log/openvpn/openvpn-status-udp.log'=>'UDP','/var/log/openvpn/openvpn-status-tcp.log'=>'TCP'] as $file=>$src){ foreach(parse_status_file($file) as $r){ $r['source']=$src; $r['gui_version']=last_gui_for_user($r['username']?:$r['common_name']); $rows[]=$r; }} return $rows; }
function oc_users(){ $csv=__DIR__.'/data/oc_users.csv'; $rows=[]; if(is_file($csv)){ foreach(file($csv, FILE_IGNORE_NEW_LINES|FILE_SKIP_EMPTY_LINES) as $l){ $p=explode('|',$l); if(($p[0]??'')!=='') $rows[]=['username'=>$p[0],'password'=>$p[1]??'','blocked'=>$p[2]??'0']; }} return $rows; }
function oc_live(){ $out=shell_exec('sudo occtl show users 2>/dev/null || occtl show users 2>/dev/null'); return trim((string)$out); }
function xray_clients(){ $f='/usr/local/etc/xray/config.json'; if(!is_file($f)) return []; $j=json_decode(file_get_contents($f),true); return $j['inbounds'][0]['settings']['clients'] ?? []; }
function xray_active_count(){ $p=escapeshellarg(vpn_env('V2_PORT','4443')); $n=trim(shell_exec("ss -Htn state established '( sport = :".vpn_env('V2_PORT','4443')." or dport = :".vpn_env('V2_PORT','4443')." )' 2>/dev/null | awk '{print $5}' | sed 's/::ffff://g' | sed 's/^\\[//;s/\\]//' | sed 's/:.*$//' | grep -E '^[0-9]+\\.[0-9]+\\.[0-9]+\\.[0-9]+$' | sort -u | wc -l")); return $n===''?'0':$n; }
function render_header($title='VPN Panel'){ ?>
<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=esc($title)?></title><link rel="stylesheet" href="style.css"></head><body><div class="shell"><header class="site-header"><div class="brand-wrap"><button class="menu-btn" type="button" onclick="document.body.classList.toggle('menu-open')">☰</button><div><div class="brand"><?=esc($title)?></div><div class="sub">Logged in as <?=esc($_SESSION['admin_user'] ?? '')?></div></div></div><a class="refresh-btn" href="<?=esc(basename($_SERVER['PHP_SELF']).(!empty($_SERVER['QUERY_STRING'])?'?'.$_SERVER['QUERY_STRING']:''))?>">Refresh</a></header><div class="layout"><aside class="sidebar"><nav class="menu"><a href="index.php">Dashboard</a><?php if(protocol_enabled('OPENVPN')): ?><a href="openvpn.php">OpenVPN Panel</a><?php endif; ?><?php if(protocol_enabled('OPENCONNECT')): ?><a href="openconnect.php">OpenConnect Panel</a><?php endif; ?><?php if(protocol_enabled('V2RAY')): ?><a href="v2ray.php">V2Ray Panel</a><?php endif; ?><a href="change_password.php">Change Admin Password</a><a href="logout.php">Logout</a></nav></aside><main class="content"><?php }
function render_footer(){ ?></main></div></div><script>document.addEventListener('click',e=>{if(window.innerWidth<981 && !e.target.closest('.sidebar') && !e.target.closest('.menu-btn')) document.body.classList.remove('menu-open');});</script></body></html><?php }
PHP
cat >"$APP_DIR/style.css" <<'CSS'
:root{--bg:#071120;--bg2:#0b1730;--panel:#0e1b34;--line:#223557;--text:#eef4ff;--muted:#9cb2d8;--blue:#4f8cff;--green:#22c793;--red:#ff5f78;--yellow:#ffbf47;--shadow:0 16px 40px rgba(0,0,0,.28)}*{box-sizing:border-box}body{margin:0;font-family:Inter,Segoe UI,Arial,sans-serif;color:var(--text);background:radial-gradient(1200px 600px at 10% 0%,#0e2450 0%,transparent 60%),linear-gradient(180deg,var(--bg),var(--bg2))}a{text-decoration:none;color:inherit}.site-header{position:sticky;top:0;z-index:60;display:flex;align-items:center;justify-content:space-between;gap:16px;padding:18px 20px;background:rgba(7,17,32,.9);backdrop-filter:blur(14px);border-bottom:1px solid rgba(255,255,255,.06)}.brand-wrap{display:flex;align-items:center;gap:14px}.brand{font-size:clamp(26px,4vw,42px);font-weight:800}.sub,.muted,.small{color:var(--muted)}.menu-btn,.refresh-btn,.btn{border:0;border-radius:14px;padding:10px 14px;cursor:pointer;color:#fff;background:var(--blue);display:inline-flex;gap:8px;align-items:center}.refresh-btn,.menu-btn{border:1px solid var(--line);background:#112246}.layout{display:flex;gap:20px;max-width:1400px;margin:0 auto;padding:20px}.sidebar{width:260px;flex:0 0 260px;background:rgba(14,27,52,.78);border:1px solid var(--line);border-radius:24px;padding:18px;box-shadow:var(--shadow);height:fit-content;position:sticky;top:96px}.menu{display:grid;gap:10px}.menu a{padding:14px 16px;border-radius:16px;background:rgba(255,255,255,.02);border:1px solid var(--line)}.content{flex:1;min-width:0}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:16px}.card{background:linear-gradient(180deg,rgba(17,31,58,.96),rgba(14,26,50,.96));border:1px solid var(--line);border-radius:24px;padding:20px;box-shadow:var(--shadow);margin-bottom:18px}.section-title{font-size:18px;font-weight:700;margin:0 0 12px}.kpi{font-size:38px;font-weight:800;margin-top:10px}.badge{display:inline-flex;border-radius:999px;padding:6px 10px;font-size:12px;border:1px solid var(--line);background:#122342}.green,.btn.green{background:var(--green)}.red,.btn.red{background:var(--red)}.yellow,.btn.yellow{background:var(--yellow);color:#1c2130}.btn.gray{background:#23375e}.toolbar{display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;margin-bottom:14px}input,textarea{width:100%;padding:13px 14px;color:var(--text);background:#091425;border:1px solid var(--line);border-radius:16px}.flash{padding:13px 16px;border-radius:16px;margin-bottom:14px;background:#12332a;border:1px solid #1d5d4f}.flash.error{background:#3d1923;border-color:#7f3343}.table-wrap{overflow:auto;border:1px solid var(--line);border-radius:18px}table{width:100%;border-collapse:collapse;min-width:850px}th,td{padding:14px 12px;border-bottom:1px solid rgba(255,255,255,.06);text-align:left;vertical-align:top}.actions{display:flex;gap:8px;flex-wrap:wrap}.code{white-space:pre-wrap;word-break:break-word;background:#08111f;border:1px solid var(--line);padding:14px;border-radius:16px;overflow:auto}.empty{padding:30px 14px;color:var(--muted);text-align:center}@media(max-width:980px){.layout{padding:14px}.sidebar{position:fixed;left:14px;top:88px;bottom:14px;width:min(84vw,320px);transform:translateX(-120%);transition:.22s;z-index:80;overflow:auto}body.menu-open .sidebar{transform:translateX(0)}.content{width:100%}table{min-width:720px}.brand{font-size:26px}}
