"badge green">Active</span>'?></td><td><form method="post" class="actions"><input type="hidden" name="action" value="edit_user"><input type="hidden" name="edit_username" value="<?=esc($name)?>"><input name="edit_password" placeholder="New password" required><button class="btn">Update</button></form></td><td><div class="actions"><a class="btn green" href="download.php?u=<?=urlencode($name)?>">Download</a><a class="btn gray" href="show_config.php?u=<?=urlencode($name)?>">Config</a><?php if((int)$u['blocked']===1): ?><a class="btn yellow" href="openvpn.php?unblock=<?=urlencode($name)?>">Unblock</a><?php else: ?><a class="btn red" href="openvpn.php?block=<?=urlencode($name)?>">Block</a><?php endif; ?><a class="btn red" href="openvpn.php?delete=<?=urlencode($name)?>" onclick="return confirm('Delete?')">Delete</a></div></td></tr><?php endforeach; ?></table></div></div><div class="card"><h2 class="section-title">OpenVPN Active Connected Devices</h2><div class="table-wrap"><table><tr><th>User</th><th>Protocol</th><th>GUI Version</th><th>Real IP</th><th>Virtual IP</th><th>Since</th><th>Download</th><th>Upload</th></tr><?php if(!$active):?><tr><td colspan="8" class="empty">No active OpenVPN devices.</td></tr><?php endif; foreach($active as $c): $u=$c['username']?:$c['common_name'];?><tr><td><b><?=esc($u)?></b></td><td><span class="badge"><?=esc($c['source'])?></span></td><td class="small"><?=esc($c['gui_version']?:'-')?></td><td><?=esc($c['real_address'])?></td><td><?=esc($c['virtual_address'])?></td><td><?=esc($c['connected_since'])?></td><td><?=esc(human_bytes($c['bytes_received']))?></td><td><?=esc(human_bytes($c['bytes_sent']))?></td></tr><?php endforeach;?></table></div></div><?php render_footer(); ?>
