cat >"$APP_DIR/change_password.php" <<'PHP'
<?php require __DIR__.'/config.php'; require_login(); $msg='';$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $cur=$_POST['current_password']??''; $new=$_POST['new_password']??''; if(admin_login($_SESSION['admin_user'],$cur)&&$new!==''){ $hash=password_hash($new,PASSWORD_DEFAULT); $st=db()->prepare('UPDATE admins SET password_hash=:h WHERE username=:u'); $st->bindValue(':h',$hash,SQLITE3_TEXT); $st->bindValue(':u',$_SESSION['admin_user'],SQLITE3_TEXT); $st->execute(); $msg='Admin password updated'; } else $err='Current password is incorrect'; } render_header('Change Admin Password'); ?><?php if($msg):?><div class="flash"><?=esc($msg)?></div><?php endif;?><?php if($err):?><div class="flash error"><?=esc($err)?></div><?php endif;?><div class="card"><form method="post"><label>Current password</label><input type="password" name="current_password" required><br><br><label>New password</label><input type="password" name="new_password" required><br><br><button class="btn">Update</button></form></div><?php render_footer(); ?>
PHP
cat >"$APP_DIR/logout.php" <<'PHP'
<?php require __DIR__.'/config.php'; session_destroy(); header('Location: login.php');
PHP
# Apache alias
cat >/etc/apache2/conf-available/vpn-panel.conf <<EOF
Alias /vpn-panel ${APP_DIR}
<Directory ${APP_DIR}>
  Options Indexes FollowSymLinks
  AllowOverride All
  Require all granted
</Directory>
EOF
a2enconf vpn-panel >/dev/null 2>&1 || true
systemctl restart apache2 >/dev/null 2>&1 || true
chown -R www-data:www-data "$APP_DIR"
chmod -R 755 "$APP_DIR"; chmod -R 777 "$DATA_DIR" "$DOWNLOAD_DIR" 2>/dev/null || true
